import random

CONCEPT_TYPE = "number_theory.crt_count"
CONCEPT_GROUP = "number_theory"

def generate(seed):
    rng = random.Random(seed)

    # Define the domain parameters
    p = rng.choice([29, 31, 41, 43, 73, 89, 97, 101, 109, 113, 127, 137, 149])
    a = rng.randint(0, p-1)
    b = rng.randint(0, p-1)

    # Calculate the Legendre symbol
    if a == 0 or b == 0:
        answer = 0
    elif pow(a, (p-1)//2, p) == 1 and pow(b, (p-1)//2, p) == 1:
        answer = 1
    elif pow(a, (p-1)//2, p) == -1 and pow(b, (p-1)//2, p) == -1:
        answer = 1
    else:
        answer = -1

    problem = (
        f"Calculate the Legendre symbol (ab/p) where a={a}, b={b}, and p={p}. "
        f"The Legendre symbol is defined as 1 if ab is a quadratic residue modulo p, -1 if it's a non-residue, and 0 if ab is divisible by p."
    )
    return problem, str(answer)

import random

CONCEPT_TYPE = "combinatorics.derangement_fixed_points"
CONCEPT_GROUP = "combinatorics"

def generate(seed):
    rng = random.Random(seed)

    # Generate a number of people (n)
    n = rng.randint(3, 10)

    # Generate the number of fixed points (k)
    k = rng.randint(0, n)

    # Calculate the number of derangements with exactly k fixed points
    def factorial(x):
        if x == 0:
            return 1
        return x * factorial(x - 1)

    def derangement_count(n, k):
        if k > n:
            return 0
        return factorial(n) // factorial(k) * (-1) ** (n - k) * factorial(n - k)

    answer = str(derangement_count(n, k))

    # Generate the problem
    problem = (
        f"How many derangements of {n} people have exactly {k} fixed points?"
    )

    return problem, answer

